196→void ULFPShopWidget::OnRelicButtonClicked()
197→{
198→	for (const auto& Pair : ButtonToRelicIndexMap)
199→	{
200→		if (Pair.Key && Pair.Key->IsHovered())
201→		{
202→			SelectedRelicIndex = Pair.Value;
203→			RefreshDetailPanel();
204→			return;
205→		}
206→	}
207→}
