 43→void ULFPShopWidget::RefreshRelicList()
 44→{
 45→	RelicButtons.Empty();
 46→	ButtonToRelicIndexMap.Empty();
 47→
 48→	if (Box_RelicList)
 49→	{
 50→		Box_RelicList->ClearChildren();
 51→	}
 52→
 53→	if (!CachedGameInstance || !Box_RelicList)
 54→	{
 55→		return;
 56→	}
 57→
 58→	for (int32 i = 0; i < CachedShopDefinition.RelicList.Num(); ++i)
 59→	{
 60→		const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[i];
 61→		FLFPRelicDefinition RelicDefinition;
 62→		if (!CachedGameInstance->FindRelicDefinition(Entry.RelicID, RelicDefinition))
 63→		{
 64→			continue;
 65→		}
 66→
 67→		UButton* RelicButton = NewObject<UButton>(this);
 68→		if (!RelicButton)
 69→		{
 70→			continue;
 71→		}
 72→
 73→		UTextBlock* Label = NewObject<UTextBlock>(RelicButton);
 74→		if (Label)
 75→		{
 76→			FString Suffix;
 77→			if (CachedGameInstance->HasRelic(Entry.RelicID))
 78→			{
 79→				Suffix = TEXT(" [已拥有]");
 80→			}
 81→			else if (!CachedGameInstance->CanAffordGold(Entry.Price))
 82→			{
 83→				Suffix = TEXT(" [金币不足]");
 84→			}
 85→
 86→			Label->SetText(FText::FromString(FString::Printf(TEXT("%s - %d%s"), *RelicDefinition.DisplayName.ToString(), Entry.Price, *Suffix)));
 87→			RelicButton->AddChild(Label);
 88→		}
 89→
 90→		UVerticalBoxSlot* ItemSlot = Box_RelicList->AddChildToVerticalBox(RelicButton);
 91→		if (ItemSlot)
 92→		{
 93→			ItemSlot->SetPadding(FMargin(4.f));
 94→		}
 95→
 96→		RelicButton->OnClicked.AddDynamic(this, &ULFPShopWidget::OnRelicButtonClicked);
 97→		RelicButtons.Add(RelicButton);
 98→		ButtonToRelicIndexMap.Add(RelicButton, i);
 99→	}
100→}
