163→bool ULFPGameInstance::TryPurchaseRelic(FName RelicID, int32 Price)
164→{
165→	if (RelicID == NAME_None)
166→	{
167→		UE_LOG(LogTemp, Warning, TEXT("TryPurchaseRelic: RelicID 无效"));
168→		return false;
169→	}
170→
171→	FLFPRelicDefinition RelicDefinition;
172→	if (!FindRelicDefinition(RelicID, RelicDefinition))
173→	{
174→		UE_LOG(LogTemp, Warning, TEXT("TryPurchaseRelic: 未找到遗物 %s"), *RelicID.ToString());
175→		return false;
176→	}
177→
178→	if (HasRelic(RelicID))
179→	{
180→		UE_LOG(LogTemp, Warning, TEXT("TryPurchaseRelic: 已拥有遗物 %s"), *RelicID.ToString());
181→		return false;
182→	}
183→
184→	if (!SpendGold(Price))
185→	{
186→		return false;
187→	}
188→
189→	OwnedRelicIDs.Add(RelicID);
190→	UE_LOG(LogTemp, Log, TEXT("购买遗物成功: %s"), *RelicID.ToString());
191→	return true;
192→}
