150→void ALFPTurnGameMode::RecordCapturedUnit(ALFPTacticsUnit* Unit)
151→{
152→    if (!Unit) return;
153→
154→    FLFPUnitEntry Entry = Unit->ToUnitEntry();
155→    if (Entry.IsValid())
156→    {
157→        CapturedUnits.Add(Entry);
158→        UE_LOG(LogTemp, Log, TEXT("捕获单位: %s, 阶级 %d"), *Entry.TypeID.ToString(), Entry.Tier);
