166→    AccumulatedDropGold += Unit->DropGold;
167→    AccumulatedDropFood += Unit->DropFood;
168→    UE_LOG(LogTemp, Log, TEXT("敌方击杀掉落: 金币 +%d, 食物 +%d (累计: %d / %d)"),
169→        Unit->DropGold, Unit->DropFood, AccumulatedDropGold, AccumulatedDropFood);
