194→void ULFPGameInstance::ApplyOwnedRelicsToUnit(ALFPTacticsUnit* Unit) const
195→{
196→	if (!Unit || !RelicDataAsset)
197→	{
198→		return;
199→	}
200→
201→	for (const FName& RelicID : OwnedRelicIDs)
202→	{
203→		FLFPRelicDefinition Definition;
204→		if (!FindRelicDefinition(RelicID, Definition))
205→		{
206→			continue;
207→		}
208→
209→		for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
210→		{
211→			switch (Effect.EffectType)
212→			{
213→			case ELFPRelicEffectType::RET_MaxHealthFlat:
214→				Unit->AddCurrentMaxHealth(Effect.Value);
215→				break;
216→			case ELFPRelicEffectType::RET_AttackFlat:
217→				Unit->AddCurrentAttack(Effect.Value);
218→				break;
219→			case ELFPRelicEffectType::RET_DefenseFlat:
220→				Unit->AddCurrentPhysicalBlock(Effect.Value);
221→				break;
222→			case ELFPRelicEffectType::RET_SpeedFlat:
223→				Unit->AddCurrentSpeed(Effect.Value);
224→				break;
225→			default:
226→				break;
227→			}
228→		}
229→	}
230→}
