102→void ULFPShopWidget::RefreshDetailPanel()
103→{
104→	if (!CachedGameInstance)
105→	{
106→		return;
107→	}
108→
109→	if (!CachedShopDefinition.RelicList.IsValidIndex(SelectedRelicIndex))
110→	{
111→		if (Text_SelectedName) Text_SelectedName->SetText(FText::FromString(TEXT("未选择遗物")));
112→		if (Text_SelectedDescription) Text_SelectedDescription->SetText(FText::GetEmpty());
113→		if (Text_SelectedPrice) Text_SelectedPrice->SetText(FText::GetEmpty());
114→		if (Text_Status) Text_Status->SetText(FText::GetEmpty());
115→		if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
116→		if (Image_SelectedRelic) Image_SelectedRelic->SetBrushFromTexture(nullptr);
117→		return;
118→	}
119→
120→	const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[SelectedRelicIndex];
121→	FLFPRelicDefinition Definition;
122→	if (!CachedGameInstance->FindRelicDefinition(Entry.RelicID, Definition))
123→	{
124→		if (Text_Status) Text_Status->SetText(FText::FromString(TEXT("遗物定义缺失")));
125→		if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
126→		return;
127→	}
128→
129→	if (Image_SelectedRelic)
130→	{
131→		Image_SelectedRelic->SetBrushFromTexture(Definition.Icon);
132→	}
133→	if (Text_SelectedName)
134→	{
135→		Text_SelectedName->SetText(Definition.DisplayName);
136→	}
137→	if (Text_SelectedDescription)
138→	{
139→		Text_SelectedDescription->SetText(FText::FromString(FString::Printf(TEXT("%s\n%s"), *Definition.Description.ToString(), *BuildEffectDescription(Definition))));
140→	}
141→	if (Text_SelectedPrice)
142→	{
143→		Text_SelectedPrice->SetText(FText::FromString(FString::Printf(TEXT("价格: %d"), Entry.Price)));
144→	}
145→
146→	bool bOwned = CachedGameInstance->HasRelic(Entry.RelicID);
147→	bool bCanAfford = CachedGameInstance->CanAffordGold(Entry.Price);
148→	if (Button_Purchase)
149→	{
150→		Button_Purchase->SetIsEnabled(!bOwned && bCanAfford);
151→	}
152→	if (Text_Status)
153→	{
154→		if (bOwned)
155→		{
156→			Text_Status->SetText(FText::FromString(TEXT("已拥有")));
157→		}
158→		else if (!bCanAfford)
159→		{
160→			Text_Status->SetText(FText::FromString(TEXT("金币不足")));
161→		}
162→		else
163→		{
164→			Text_Status->SetText(FText::FromString(TEXT("可购买")));
165→		}
166→	}
167→}
