 86→bool ULFPSkillComponent::ExecuteSkill(ULFPSkillBase* Skill, ALFPHexTile* TargetTile)
 87→{
 88→    ALFPTacticsUnit* OwnerUnit = Cast<ALFPTacticsUnit>(GetOwner());
 89→    if (!OwnerUnit || !Skill) return false;
 90→
 91→    if (!OwnerUnit->IsEnemy())
 92→    {
 93→		// 检查技能是否可用
 94→		if (!Skill->CanExecute(TargetTile)) return false;
 95→    }
 96→
 97→    // 执行技能
 98→    Skill->Execute(TargetTile);
 99→
100→    // 更新技能优先级（降低已使用技能的优先级）
101→    Skill->OnSkillUsed();
102→
103→    // 广播事件
104→    OnSkillExecuted.Broadcast(OwnerUnit, TargetTile);
105→
106→    return true;
107→}
