57→TArray<int32> ULFPWorldMapPlayerState::GetReachableNodeIDs(ALFPWorldMapManager* Manager) const
58→{
59→	TArray<int32> Result;
60→	if (!Manager) return Result;
61→
62→	TArray<ALFPWorldMapNode*> Neighbors = Manager->GetNeighbors(CurrentNodeID);
63→	for (ALFPWorldMapNode* Neighbor : Neighbors)
64→	{
65→		if (!Neighbor) continue;
66→
67→		// 检查解锁条件（前置节点必须已访问）
68→		bool bUnlocked = true;
69→		if (!Neighbor->PrerequisiteNodeIDs.IsEmpty())
70→		{
71→			TArray<FString> PrereqIDs;
72→			Neighbor->PrerequisiteNodeIDs.ParseIntoArray(PrereqIDs, TEXT(";"), true);
73→			for (const FString& IDStr : PrereqIDs)
74→			{
75→				int32 PrereqID = FCString::Atoi(*IDStr);
76→				if (!VisitedNodeIDs.Contains(PrereqID))
77→				{
78→					bUnlocked = false;
79→					break;
80→				}
81→			}
82→		}
83→
84→		if (bUnlocked)
85→		{
86→			Result.Add(Neighbor->NodeID);
87→		}
88→	}
89→
90→	return Result;
91→}
