168→FString ULFPShopWidget::BuildEffectDescription(const FLFPRelicDefinition& Definition) const
169→{
170→	TArray<FString> Parts;
171→	for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
172→	{
173→		switch (Effect.EffectType)
174→		{
175→		case ELFPRelicEffectType::RET_MaxHealthFlat:
176→			Parts.Add(FString::Printf(TEXT("最大生命 %+d"), Effect.Value));
177→			break;
178→		case ELFPRelicEffectType::RET_AttackFlat:
179→			Parts.Add(FString::Printf(TEXT("攻击力 %+d"), Effect.Value));
180→			break;
181→		case ELFPRelicEffectType::RET_DefenseFlat:
182→			Parts.Add(FString::Printf(TEXT("防御力 %+d"), Effect.Value));
183→			break;
184→		case ELFPRelicEffectType::RET_SpeedFlat:
185→			Parts.Add(FString::Printf(TEXT("速度 %+d"), Effect.Value));
186→			break;
187→		default:
188→			break;
189→		}
190→	}
191→
192→	return Parts.Num() > 0 ? FString::Join(Parts, TEXT("\n")) : TEXT("无效果");
193→}
