290→TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
291→{
292→	// 统计每个 TypeID 的出现次数
293→	TMap<FName, int32> CountMap;
294→
295→	for (const FLFPUnitEntry& Unit : PartyUnits)
296→	{
297→		if (Unit.IsValid())
298→		{
299→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
300→		}
301→	}
302→	for (const FLFPUnitEntry& Unit : ReserveUnits)
303→	{
304→		if (Unit.IsValid())
305→		{
306→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
307→		}
308→	}
309→
310→	// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
311→	TArray<FLFPUnitEntry> Result;
312→	for (const auto& Pair : CountMap)
313→	{
314→		if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
315→		{
316→			FLFPUnitEntry Entry;
317→			Entry.TypeID = Pair.Key;
318→			Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
319→			Result.Add(Entry);
320→		}
321→	}
322→
323→	return Result;
324→}
325→
326→bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
327→	bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
328→{
329→	TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
330→	TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
331→
332→	if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
333→	{
334→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
335→		return false;
336→	}
337→
338→	const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
339→	const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
340→
341→	// 验证两个源单位 TypeID 相同
342→	if (UnitA.TypeID != UnitB.TypeID)
343→	{
344→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
345→			*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
346→		return false;
347→	}
348→
349→	// 验证 TargetTypeID 在进化目标列表中
350→	if (!UnitRegistry)
351→	{
352→		UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
353→		return false;
354→	}
355→
356→	TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
357→	if (!Targets.Contains(TargetTypeID))
358→	{
359→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
360→			*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
361→		return false;
362→	}
363→
364→	// 创建进化后的新单位
365→	FLFPUnitEntry NewUnit;
366→	NewUnit.TypeID = TargetTypeID;
367→	NewUnit.Tier = UnitRegistry->GetUnitTier(TargetTypeID);
368→
369→	// 移除两个源单位（同一数组时先移除大索引避免偏移）
370→	if (bSourceAIsParty == bSourceBIsParty)
371→	{
372→		int32 First = FMath::Max(SourceAIndex, SourceBIndex);
373→		int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
374→		ArrayA.RemoveAt(First);
375→		ArrayA.RemoveAt(Second);
376→	}
377→	else
378→	{
379→		ArrayA.RemoveAt(SourceAIndex);
380→		ArrayB.RemoveAt(SourceBIndex);
381→	}
382→
383→	TryAddUnit(NewUnit);
384→
385→	UE_LOG(LogTemp, Log, TEXT("进化成功: %s × 2 → %s (T%d)"),
386→		*UnitA.TypeID.ToString(), *TargetTypeID.ToString(), NewUnit.Tier);
387→
388→	return true;
389→}
