  9→void ALFPWorldMapGameMode::StartPlay()
 10→{
 11→	Super::StartPlay();
 12→
 13→	// 生成世界地图管理器
 14→	if (!WorldMapManagerClass)
 15→	{
 16→		UE_LOG(LogTemp, Warning, TEXT("WorldMapManagerClass 未配置"));
 17→		return;
 18→	}
 19→
 20→	FActorSpawnParameters SpawnParams;
 21→	SpawnParams.Owner = this;
 22→	WorldMapManager = GetWorld()->SpawnActor<ALFPWorldMapManager>(
 23→		WorldMapManagerClass, FVector::ZeroVector, FRotator::ZeroRotator, SpawnParams);
 24→
 25→	if (!WorldMapManager)
 26→	{
 27→		UE_LOG(LogTemp, Error, TEXT("世界地图管理器生成失败"));
 28→		return;
 29→	}
 30→
 31→	UE_LOG(LogTemp, Log, TEXT("世界地图管理器已生成"));
 32→
 33→	// 从 GameInstance 获取状态
 34→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 35→	if (GI && GI->GetWorldMapSnapshot().bIsValid)
 36→	{
 37→		// 从快照恢复
 38→		const FLFPWorldMapSnapshot& Snapshot = GI->GetWorldMapSnapshot();
 39→		UE_LOG(LogTemp, Log, TEXT("从快照恢复世界地图: %s, 节点 %d, 回合 %d"),
 40→			*Snapshot.WorldMapName, Snapshot.CurrentNodeID, Snapshot.CurrentTurn);
 41→
 42→		// 加载地图
 43→		WorldMapManager->LoadWorldMap(Snapshot.WorldMapName);
 44→
 45→		// 恢复玩家状态
 46→		WorldMapManager->InitializePlayer(Snapshot.CurrentNodeID);
 47→		if (ULFPWorldMapPlayerState* PS = WorldMapManager->GetPlayerState())
 48→		{
 49→			PS->CurrentTurn = Snapshot.CurrentTurn;
 50→			PS->VisitedNodeIDs = Snapshot.VisitedNodeIDs;
 51→			PS->RevealedNodeIDs = Snapshot.RevealedNodeIDs;
 52→		}
 53→
 54→		// 恢复已触发节点
 55→		WorldMapManager->RestoreTriggeredNodes(Snapshot.TriggeredNodeIDs);
 56→
 57→		// 更新迷雾
 58→		WorldMapManager->UpdateFog();
 59→
 60→		// 处理战斗结果
 61→		if (GI->HasPendingBattleResult())
 62→		{
 63→			FLFPBattleResult Result = GI->ConsumeBattleResult();
 64→			HandleBattleResult(Result);
 65→		}
 66→	}
 67→	else if (!DefaultWorldMapName.IsEmpty())
 68→	{
 69→		// 首次进入：加载默认地图
 70→		UE_LOG(LogTemp, Log, TEXT("首次进入世界地图: %s"), *DefaultWorldMapName);
 71→		WorldMapManager->LoadWorldMap(DefaultWorldMapName);
 72→		WorldMapManager->InitializePlayer(DefaultStartNodeID);
 73→	}
 74→	else
 75→	{
 76→		// 没有地图可加载（编辑器模式或测试）
 77→		UE_LOG(LogTemp, Log, TEXT("无地图配置，空世界地图"));
 78→	}
 79→}
