    // 延时结束后执行当前敌人的规划
    void ExecuteCurrentEnemyPlan();

    // 敌人规划阶段移动完成回调
    UFUNCTION()
    void OnEnemyPlanMoveComplete();

    // 结束敌人规划阶段
    void EndEnemyPlanningPhase();

    // ==== 行动阶段 ====

    // 开始行动阶段
    void BeginActionPhase();

