{
	if (bIsDead) return;

	CurrentHealth = FMath::Min(CurrentHealth + Amount, GetCurrentMaxHealth());

	// 广播血量变化事件
	OnHealthChangedDelegate.Broadcast(CurrentHealth, GetCurrentMaxHealth());

	// 蓝图事件
	OnHeal(Amount);
}

