void ULFPHealthBarWidget::NativeConstruct()
{
	Super::NativeConstruct();

	// 确保控件已绑定
	if (HealthProgressBar && HealthText)
	{
		// 初始化满血条
		//SetVisibility(ESlateVisibility::Hidden);
