269	bool ALFPBattleRelicRuntimeManager::EvaluateConditions(const TArray<FLFPRelicCondition>& Conditions, ALFPTacticsUnit* Unit) const
270	{
271		if (!Unit)
272		{
273			return false;
274		}
275	
276		for (const FLFPRelicCondition& Condition : Conditions)
277		{
278			switch (Condition.ConditionType)
279			{
280			case ELFPRelicConditionType::RCT_None:
281				break;
282			case ELFPRelicConditionType::RCT_HealthPercentBelow:
283			{
284				const float HealthPercent = Unit->GetCurrentMaxHealth() > 0
285					? static_cast<float>(Unit->GetCurrentHealth()) / Unit->GetCurrentMaxHealth()
286					: 0.f;
287				if (HealthPercent >= Condition.FloatValue)
288				{
289					return false;
290				}
291				break;
292			}
293			case ELFPRelicConditionType::RCT_HasRelic:
294			{
295				bool bHasAnyRelic = false;
296				for (const FName& RelicID : Condition.RelicIDs)
297				{
298					if (OwnedRelicIDs.Contains(RelicID))
299					{
300						bHasAnyRelic = true;
301						break;
302					}
303				}
304				if (!bHasAnyRelic)
305				{
306					return false;
307				}
308				break;
309			}
310			case ELFPRelicConditionType::RCT_HasAllRelics:
311			{
312				for (const FName& RelicID : Condition.RelicIDs)
313				{
314					if (!OwnedRelicIDs.Contains(RelicID))
315					{
316						return false;
317					}
318				}
319				break;
320			}
321			default:
322				return false;
323			}
324		}
325	
326		return true;
327	}
