329	void ALFPBattleRelicRuntimeManager::ApplyEffects(const TArray<FLFPRelicBattleEffect>& Effects, ALFPTacticsUnit* Unit)
330	{
331		if (!Unit)
332		{
333			return;
334		}
335	
336		for (const FLFPRelicBattleEffect& Effect : Effects)
337		{
338			switch (Effect.EffectType)
339			{
340			case ELFPRelicBattleEffectType::RBET_HealFlat:
341				Unit->Heal(Effect.IntValue);
342				break;
343			case ELFPRelicBattleEffectType::RBET_ModifyStatFlat:
344				switch (Effect.StatType)
